'use client';

import { useTranslation } from '@/components/providers/LanguageProvider';

export function LanguageToggle() {
  const { locale, setLocale, t } = useTranslation();

  const toggleLanguage = () => {
    setLocale(locale === 'zh' ? 'en' : 'zh');
  };

  return (
    <button
      onClick={toggleLanguage}
      className="inline-flex items-center justify-center px-3 py-2 rounded-md text-sm font-medium transition-colors duration-fast hover:bg-muted focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 dark:focus:ring-offset-background"
      aria-label={`Switch to ${locale === 'zh' ? 'English' : 'Chinese'}`}
      title={locale === 'zh' ? 'Switch to English' : '切换到中文'}
    >
      {locale === 'zh' ? t('language.en') : t('language.zh')}
    </button>
  );
}
